    const targetModel = model || DEFAULT_GEMINI_MODEL;

    const config: any = { 
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT, // OPTIMIZATION: Return single object, not Array
            properties: {
                clauseId: { type: Type.STRING },
