export const useDebounce = <T,>(value: T, delay: number): T => {
    const [debouncedValue, setDebouncedValue] = useState(value);
    useEffect(() => {
        const handler = setTimeout(() => {
            setDebouncedValue(value);
        }, delay);
        return () => {
            clearTimeout(handler);
        };
    }, [value, delay]);
    return debouncedValue;
};

export const copyToClipboard = (text: string) => {
    if (!text) return;
    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).catch(() => fallbackCopy(text));
    } else { fallbackCopy(text); }
};

const fallbackCopy = (text: string) => {
    const textArea = document.createElement("textarea"); textArea.value = text;
    textArea.style.position = "fixed"; textArea.style.left = "-9999px";
    document.body.appendChild(textArea); textArea.focus(); textArea.select();
    try { document.execCommand('copy'); } catch (err) { console.error(err); }
    document.body.removeChild(textArea);
};

export const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve((reader.result as string).split(',')[1]); 
        reader.onerror = error => reject(error);
    });
};

export const extractTextFromPdf = async (file: File): Promise<string> => {
    if (!window.pdfjsLib) {
        throw new Error("PDF.js library not loaded");
    }

    const arrayBuffer = await file.arrayBuffer();
    const pdf = await window.pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = "";

    for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const textContent = await page.getTextContent();
        const pageText = textContent.items.map((item: any) => item.str).join(" ");
        fullText += pageText + "\n\n";
    }

    return fullText;
};

// MOVED FROM APP.TSX
export const processSourceFile = async (file: File): Promise<string> => {
    let text = "";
    try {
        if (file.name.toLowerCase().endsWith('.pdf')) {
            text = await extractTextFromPdf(file);
        } else if (file.name.toLowerCase().endsWith('.docx')) {
            if (typeof mammoth === 'undefined') throw new Error("Mammoth library missing");
            const arrayBuffer = await file.arrayBuffer();
            const result = await mammoth.extractRawText({ arrayBuffer });
            text = result.value;
        } else if (file.name.toLowerCase().endsWith('.doc')) {
            throw new Error("Legacy Word (.doc) files are not supported due to browser limitations. Please save your file as .docx and try again.");
        } else {
            text = await file.text();
        }
        if (!text || text.length < 50) throw new Error("File content is too short or empty.");
        return text;
    } catch (err: any) {
        console.error("File processing error:", err);
        throw new Error(`Failed to parse ${file.name}: ${err.message}`);
    }
};

export const cleanAndParseJSON = (text: string) => {
    if (!text) return null;
    let cleanText = text.trim();
    if (cleanText.startsWith("```")) {
        cleanText = cleanText.replace(/^```(json)?/, "").replace(/```$/, "");
    }
    const firstBracket = cleanText.indexOf('[');
    const firstCurly = cleanText.indexOf('{');
    const lastBracket = cleanText.lastIndexOf(']');
    const lastCurly = cleanText.lastIndexOf('}');
    if (firstBracket !== -1 && lastBracket !== -1 && (firstCurly === -1 || firstBracket < firstCurly)) {
            cleanText = cleanText.substring(firstBracket, lastBracket + 1);
    } else if (firstCurly !== -1 && lastCurly !== -1) {
            cleanText = cleanText.substring(firstCurly, lastCurly + 1);
    }
    try {
        return JSON.parse(cleanText);
    } catch (error) {
        console.error("JSON Parse Error on text:", cleanText);
        return null;
    }
};

export const cleanFileName = (str: string) => {
    if (!str) return 'N_A';
    return str.replace(/[^a-zA-Z0-9\s]/g, '').trim().replace(/\s+/g, '_').substring(0, 30);
};

import React, { useRef, useState, useEffect } from 'react';
import { Icon } from './UI';
import { TABS_CONFIG } from '../constants';

interface TabNavigationProps {
    layoutMode: string;
    setLayoutMode: (mode: any) => void;
    isSidebarOpen: boolean;
    sidebarWidth: number; // Needed to trigger resize recalc
}

export const TabNavigation: React.FC<TabNavigationProps> = ({ 
    layoutMode, 
    setLayoutMode, 
    isSidebarOpen,
    sidebarWidth 
}) => {
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });

    // --- LIQUID TABS EFFECT LOGIC ---
    useEffect(() => {
        const updateTabIndicator = () => {
            const activeIndex = TABS_CONFIG.findIndex(t => t.id === layoutMode);
            const activeEl = tabsRef.current[activeIndex];
            if (activeEl) {
                setTabStyle({
                    left: activeEl.offsetLeft,
                    width: activeEl.offsetWidth,
                    opacity: 1,
                    color: TABS_CONFIG[activeIndex].colorClass
                });
            }
        };

        // Execute immediately
        updateTabIndicator();

        // Execute on resize and when sidebar toggles (animations)
        window.addEventListener('resize', updateTabIndicator);
        // Short delay to allow DOM to settle after sidebar animation
        const timer = setTimeout(updateTabIndicator, 300); 

        return () => {
            window.removeEventListener('resize', updateTabIndicator);
            clearTimeout(timer);
        };
    }, [layoutMode, isSidebarOpen, sidebarWidth]);

    return (
        <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-100 dark:bg-slate-950 p-1 rounded-xl w-full dark:shadow-[inset_0_1px_3px_rgba(0,0,0,0.5)]">
            <div 
                className={`absolute top-1 bottom-1 shadow-sm rounded-lg transition-all duration-500 ease-fluid z-0 ${tabStyle.color}`} 
                style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity }} 
            />
            {TABS_CONFIG.map((tab, idx) => (
                <button 
                    key={tab.id} 
                    ref={el => { tabsRef.current[idx] = el; }} 
                    onClick={() => setLayoutMode(tab.id)} 
                    className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2 rounded-lg text-xs md:text-sm font-bold transition-colors duration-300 ${layoutMode === tab.id ? 'text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200'}`}
                >
                    <Icon name={tab.icon} size={16}/> 
                    <span className={`${isSidebarOpen ? 'hidden xl:inline' : 'hidden md:inline'}`}>{tab.label}</span>
                </button>
            ))}
        </div>
    );
};

