                INPUT TEXT:
                """
                ${chunk}
                """`;

                result = await executeWithSmartFailover((key, model) => generateTextReport(prompt, "Professional ISO Translator", key, model));

                setExportState(prev => {
                    const newResults = [...prev.results];
